import subprocess, sys, json
from pathlib import Path
import anthropic

client = anthropic.Anthropic()
MODEL = "claude-opus-4-5"

TOOLS = [
    {
        "name": "read_file",
        "description": "Read the full text of a file from disk.",
        "input_schema": {
            "type": "object",
            "properties": {"path": {"type": "string"}},
            "required": ["path"]
        }
    },
    {
        "name": "write_file",
        "description": "Write text content to a file, creating it if needed.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string"},
                "content": {"type": "string"}
            },
            "required": ["path", "content"]
        }
    },
    {
        "name": "run_bash",
        "description": "Execute a bash command and return stdout + stderr.",
        "input_schema": {
            "type": "object",
            "properties": {"command": {"type": "string"}},
            "required": ["command"]
        }
    }
]

def dispatch(tool_name, tool_input):
    if tool_name == "read_file":
        return Path(tool_input["path"]).read_text(errors="replace")
    elif tool_name == "write_file":
        p = Path(tool_input["path"])
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(tool_input["content"])
        return f"Wrote {p}"
    elif tool_name == "run_bash":
        result = subprocess.run(
            tool_input["command"], shell=True,
            capture_output=True, text=True, timeout=30
        )
        return (result.stdout + result.stderr).strip() or "(no output)"
    return f"Unknown tool: {tool_name}"

def run_agent(task):
    messages = [{"role": "user", "content": task}]
    while True:
        response = client.messages.create(
            model=MODEL, max_tokens=4096,
            tools=TOOLS, messages=messages
        )
        messages.append({"role": "assistant", "content": response.content})
        if response.stop_reason == "end_turn":
            # Final answer - no tool calls
            for block in response.content:
                if hasattr(block, "text"):
                    print(block.text)
            break
        # Dispatch all tool_use blocks
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                print(f"[tool] {block.name}({json.dumps(block.input)[:80]})", flush=True)
                result = dispatch(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result
                })
        messages.append({"role": "user", "content": tool_results})

if __name__ == "__main__":
    run_agent(" ".join(sys.argv[1:]) or "List the Python files in the current directory.")
